    mutationFn: async (feedbackId: number) => {
      const response = await authenticatedRequest("DELETE", `/api/feedback/${feedbackId}`);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/feedback"] });
      toast({
        title: "Success",
        description: "Feedback deleted successfully!",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete feedback",
        variant: "destructive",
      });
    },
  });

  const handleDeleteFeedback = (feedbackId: number) => {
    if (window.confirm("Are you sure you want to delete this feedback? This action cannot be undone.")) {
      deleteFeedbackMutation.mutate(feedbackId);
    }
  };


  const { data: feedbackData, isLoading, error } = useQuery({
    queryKey: ["/api/feedback"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/feedback");
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      return await response.json();
    },
    refetchOnWindowFocus: false,
    retry: 3,
  });

  const { data: interviewsData } = useQuery({
    queryKey: ["/api/interviews"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/interviews");
      return await response.json();
    },
  });

  const { data: feedbackTypesData } = useQuery({
    queryKey: ["/api/feedback-types"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/feedback-types");
      return await response.json();
    },
  });

  const feedbackList = feedbackData?.feedback || [];
  const interviews = interviewsData?.requests || [];
  const feedbackTypes = feedbackTypesData?.feedbackTypes || [];

  // Debug logging
  console.log("Feedback data:", feedbackData);
  console.log("Feedback list:", feedbackList);
  console.log("Loading state:", isLoading);
  console.log("Error state:", error);

  // Date filtering functions
  const isToday = (date: string): boolean => {
    const today = new Date();
    const entryDate = new Date(date);
    return entryDate.toDateString() === today.toDateString();
  };

  const isThisWeek = (date: string): boolean => {
    const today = new Date();
    const entryDate = new Date(date);
    const weekStart = new Date(today.setDate(today.getDate() - today.getDay()));
    return entryDate >= weekStart;
  };

  const isThisMonth = (date: string): boolean => {
    const today = new Date();
    const entryDate = new Date(date);
    return entryDate.getMonth() === today.getMonth() && entryDate.getFullYear() === today.getFullYear();
  };

  const matchesCustomDate = (date: string): boolean => {
    if (!customDate) return true;
    const entryDate = new Date(date);
    const targetDate = new Date(customDate);
    return entryDate.toDateString() === targetDate.toDateString();
  };

  // Auto-refresh effect
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (autoRefresh) {
      interval = setInterval(() => {
        queryClient.invalidateQueries({ queryKey: ["/api/feedback"] });
      }, 30000); // Refresh every 30 seconds
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [autoRefresh]);

  const filteredFeedback = feedbackList.filter((item: any) => {
    const matchesType = typeFilter === "all" || item.type === typeFilter;

    const matchesSearch = searchTerm === "" || 
      item.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (item.submittedBy?.firstName + " " + item.submittedBy?.lastName).toLowerCase().includes(searchTerm.toLowerCase());

    // Date filtering
    let matchesDate = true;
    switch (dateFilter) {
      case "today":
        matchesDate = isToday(item.createdAt);
        break;
      case "week":
        matchesDate = isThisWeek(item.createdAt);
        break;
      case "month":
        matchesDate = isThisMonth(item.createdAt);
        break;
      case "custom":
        matchesDate = matchesCustomDate(item.createdAt);
        break;
      case "all":
      default:
        matchesDate = true;
        break;
    }

    return matchesType && matchesSearch && matchesDate;
  });

  const getTypeColor = (type: string) => {
    switch (type) {
      case "interview_feedback":
        return "bg-blue-100 text-blue-800";
      case "general_feedback":
        return "bg-green-100 text-green-800";
      case "system_improvement":
        return "bg-purple-100 text-purple-800";
      case "user_experience":
        return "bg-orange-100 text-orange-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getRatingStars = (rating: string) => {
    const stars = [];
    const ratingNum = parseInt(rating);
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Star
          key={i}
          className={`w-4 h-4 ${
            i <= ratingNum ? "text-yellow-400 fill-current" : "text-gray-300"
          }`}
        />
      );
    }
    return stars;
  };

  const getRelatedInterviewTitle = (interviewId: number) => {
    const interview = interviews.find((i: any) => i.id === interviewId);
    return interview ? `${interview.position} - ${interview.candidateName}` : "Unknown Interview";
  };

  if (isLoading) {
    return (
      <div className="animate-pulse">
        <div className="mb-8">
          <div className="h-8 bg-gray-200 rounded w-64 mb-2"></div>
          <div className="h-4 bg-gray-200 rounded w-96"></div>
        </div>
        <div className="space-y-6">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-48 bg-gray-200 rounded-xl"></div>
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <DashboardLayout>
        <div className="p-6">
          <Card>
            <CardContent className="p-6">
              <h3 className="text-lg font-medium text-red-600 mb-2">Error Loading Feedback</h3>
              <p className="text-gray-600">{error.message}</p>
              <pre className="mt-4 p-4 bg-gray-100 rounded text-sm overflow-auto">
                {JSON.stringify(error, null, 2)}
              </pre>
            </CardContent>
          </Card>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div>

      {/* Create New Feedback Button */}
      <div className="mb-6 flex justify-end">
        <Button onClick={() => setShowFeedbackModal(true)} className="bg-blue-600 hover:bg-blue-700">
          <Plus className="w-4 h-4 mr-2" />
          Create New Feedback
        </Button>
      </div>

      {/* Search and Filter Controls */}
      <Card className="mb-6">
        <CardContent className="p-6">
          <div className="space-y-6">
            {/* Search Bar */}
            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-1">
                <div className="relative">
                  <Search className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
                  <Input
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                    aria-label="Search feedback by title, description, or author"
                  />
                </div>
              </div>
              <div className="flex gap-2 w-full md:w-auto">
                <Select value={typeFilter} onValueChange={setTypeFilter}>
                  <SelectTrigger className="w-full md:w-48">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Types</SelectItem>
                    {/* Default types */}
                    <SelectItem value="interview_feedback">Interview Feedback</SelectItem>
                    <SelectItem value="general_feedback">General Feedback</SelectItem>
                    <SelectItem value="system_improvement">System Improvement</SelectItem>
                    <SelectItem value="user_experience">User Experience</SelectItem>
                    {/* Dynamic types */}
                    {feedbackTypes.map((type: any) => (
                      <SelectItem key={type.id} value={type.name}>
                        {type.displayName}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Button 
                  variant="outline" 
                  size="sm"
                  onClick={() => setShowAddTypeModal(true)}
                  className="shrink-0"
                >
                  <Plus className="w-4 h-4" />
                </Button>
              </div>
            </div>

            {/* Date Filter Controls */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 bg-gray-50 p-4 rounded-lg border">
              <div className="space-y-2">
                <Label htmlFor="date-filter" className="text-sm font-medium flex items-center gap-2">
                  <Calendar className="w-4 h-4" />
                  Date Filter
                </Label>
                <Select value={dateFilter} onValueChange={setDateFilter}>
                  <SelectTrigger id="date-filter">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="today">Today Only</SelectItem>
                    <SelectItem value="week">This Week</SelectItem>
                    <SelectItem value="month">This Month</SelectItem>
                    <SelectItem value="custom">Custom Date</SelectItem>
                    <SelectItem value="all">All Dates</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {dateFilter === 'custom' && (
                <div className="space-y-2">
                  <Label htmlFor="custom-date" className="text-sm font-medium">
                    Select Date
                  </Label>
                  <Input
                    id="custom-date"
                    type="date"
                    value={customDate}
                    onChange={(e) => setCustomDate(e.target.value)}
                    className="border-gray-200 focus:border-blue-500 focus:ring-blue-500"
                  />
                </div>
              )}

              <div className="space-y-2">
                <Label htmlFor="auto-refresh" className="text-sm font-medium flex items-center gap-2">
                  <RefreshCw className={`w-4 h-4 ${autoRefresh ? 'animate-spin text-green-600' : 'text-gray-400'}`} />
                  Auto Refresh
                </Label>
                <div className="flex items-center space-x-2">
                  <Switch
                    id="auto-refresh"
                    checked={autoRefresh}
                    onCheckedChange={setAutoRefresh}
                  />
                  <span className="text-sm text-gray-600">
                    {autoRefresh ? 'Every 30s' : 'Disabled'}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>


      {/* Feedback List */}
      <div className="space-y-6">
        {filteredFeedback.length === 0 ? (
          <Card>
            <CardContent className="p-12 text-center">
              <MessageSquare className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No feedback found</h3>
              <p className="text-gray-600 mb-4">
                {typeFilter === "all" 
                  ? "No feedback has been submitted yet."
                  : `No ${typeFilter.replace('_', ' ')} feedback found.`
                }
              </p>
              <Button onClick={() => setShowFeedbackModal(true)}>
                <Plus className="w-4 h-4 mr-2" />
                Submit First Feedback
              </Button>
            </CardContent>
          </Card>
        ) : (
          filteredFeedback.map((item: any) => (
            <Card key={item.id}>
              <CardContent className="p-6">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center space-x-3 mb-3">
                      <h3 className="text-lg font-semibold text-gray-900">{item.title}</h3>
                      <Badge className={getTypeColor(item.type)}>
                        {item.type.replace('_', ' ').replace(/\b\w/g, (l: string) => l.toUpperCase())}
                      </Badge>
                      {item.rating && (
                        <div className="flex space-x-1">
                          {getRatingStars(item.rating)}
                        </div>
                      )}
                    </div>

                    <p className="text-gray-700 mb-4">{item.description}</p>

                    {item.relatedInterviewId && (
                      <div className="mb-4">
                        <p className="text-sm font-medium text-gray-500 mb-1">Related Interview:</p>
                        <p className="text-sm text-gray-900">
                          {getRelatedInterviewTitle(item.relatedInterviewId)}
                        </p>
                      </div>
                    )}

                    <div className="flex items-center justify-between text-sm text-gray-500">
                      <div className="flex items-center space-x-4">
                        <span>
                          By {item.submittedBy?.firstName || "Unknown"} {item.submittedBy?.lastName || "User"}
                        </span>
                        <span>•</span>
                        <span>{getRelativeTime(item.createdAt)}</span>
                      </div>

                      {(user?.role === "admin" || user?.role === "manager") && (
                        <div className="flex space-x-2">
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => {
                              setSelectedFeedback(item);
                              setShowCommentsModal(true);
                            }}
                          >
                            Comments
                          </Button>
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => {
                              setSelectedFeedback(item);
                              setShowDetailsModal(true);
                            }}
                          >
                            Details
                          </Button>
                          <Button variant="outline" size="sm">
                            Archive
                          </Button>
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => handleDeleteFeedback(item.id)}
                            disabled={deleteFeedbackMutation.isPending}
                            className="text-red-600 hover:text-red-700 border-red-200 hover:border-red-300"
                          >
                            <Trash2 className="w-4 h-4 mr-1" />
                            {deleteFeedbackMutation.isPending ? "Deleting..." : "Delete"}
                          </Button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>

      <FeedbackModal 
        open={showFeedbackModal} 
        onOpenChange={setShowFeedbackModal} 
        interviews={interviews}
      />

      {/* Details Modal */}
      <Dialog open={showDetailsModal} onOpenChange={setShowDetailsModal}>
        <DialogContent className="sm:max-w-4xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold">Feedback Details & Comment History</DialogTitle>
          </DialogHeader>

          {selectedFeedback && (
            <div className="space-y-6">
              {/* Feedback Summary */}
              <Card className="bg-gray-50 border-l-4 border-l-blue-500">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="text-lg font-semibold">{selectedFeedback.title}</h3>
                    <Badge className={getTypeColor(selectedFeedback.type)}>
                      {selectedFeedback.type.replace('_', ' ').replace(/\b\w/g, (l: string) => l.toUpperCase())}
                    </Badge>
                  </div>
                  <p className="text-gray-700 mb-3">{selectedFeedback.description}</p>
                  <div className="flex items-center justify-between text-sm text-gray-600">
                    <div className="flex items-center space-x-4">
                      <span className="flex items-center gap-1">
                        <User className="w-4 h-4" />
                        {selectedFeedback.submittedBy?.firstName || "Unknown"} {selectedFeedback.submittedBy?.lastName || "User"}
                      </span>
                      <span className="flex items-center gap-1">
                        <Calendar className="w-4 h-4" />
                        {new Date(selectedFeedback.createdAt).toLocaleDateString()}
                      </span>
                    </div>
                    {selectedFeedback.rating && (
                      <div className="flex space-x-1">
                        {getRatingStars(selectedFeedback.rating)}
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>

              {/* Comment History Section */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h4 className="text-lg font-semibold flex items-center gap-2">
                    <MessageSquare className="w-5 h-5" />
                    Comment History
                  </h4>
                  <Badge variant="outline">{comments.length} Comments</Badge>
                </div>

                {/* Comment History */}
                <div className="space-y-3">
                  {comments.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                      <p>No comments yet. Be the first to add one!</p>
                    </div>
                  ) : (
                    comments.map((comment, index) => (
                      <Card key={index} className="border-l-4 border-l-blue-500">
                        <CardContent className="p-4">
                          <div className="flex items-start justify-between mb-2">
                            <div className="flex items-center space-x-2">
                              <span className="font-medium text-sm">{comment.author}</span>
                              <Badge variant="outline" className="text-xs">{comment.role}</Badge>
                            </div>
                            <span className="text-xs text-gray-500">{comment.timestamp}</span>
                          </div>
                          <p className="text-sm text-gray-700">{comment.text}</p>
                        </CardContent>
                      </Card>
                    ))
                  )}
                </div>

                {/* Add Comment Section */}
                <Card className="bg-blue-50 border-blue-200">
                  <CardContent className="p-4">
                    <h5 className="font-medium mb-3">{t("addCommentLabel")}</h5>
                    <div className="space-y-3">
                      <div className="space-y-2">
                        <Label htmlFor="detail-comment">{t("addCommentLabel")}</Label>
                        <textarea 
                          id="detail-comment"
                          className="w-full p-3 border border-gray-300 rounded-md resize-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                          value={detailComment}
                          onChange={(e) => setDetailComment(e.target.value)}
                          rows={3}
                        />
                        <p className="text-sm text-gray-600">{t("commentGuidance")}</p>
                      </div>
                      <div className="flex justify-end space-x-2">
                        <Button variant="outline" size="sm" onClick={() => setDetailComment("")}>Cancel</Button>
                        <Button 
                          size="sm"
                          onClick={() => {
                            if (detailComment.trim()) {
                              const newCommentObj = {
                                text: detailComment,
                                author: user?.username || "Current User",
                                role: user?.role || "User",
                                timestamp: "Just now"
                              };
                              setComments(prev => [newCommentObj, ...prev]);
                              toast({
                                title: "Success",
                                description: "Comment added successfully",
                              });
                              setDetailComment("");
                            } else {
                              toast({
                                title: "Error",
                                description: "Please enter a comment",
                                variant: "destructive"
                              });
                            }
                          }}
                          disabled={!detailComment.trim()}
                        >
                          Add Comment
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Comments Modal */}
      <Dialog open={showCommentsModal} onOpenChange={setShowCommentsModal}>
        <DialogContent className="sm:max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold">Comments</DialogTitle>
          </DialogHeader>

          {selectedFeedback && (
            <div className="space-y-4">
              {/* Feedback Info */}
              <div className="bg-gray-50 p-4 rounded-lg border-l-4 border-l-blue-500">
                <h3 className="font-semibold text-lg">{selectedFeedback.title}</h3>
                <p className="text-sm text-gray-600 mt-1">{selectedFeedback.description}</p>
              </div>

              {/* Comments List */}
              <div className="space-y-3">
                <h4 className="font-medium">Comments</h4>

                {/* Comment List */}
                <div className="space-y-3">
                  {comments.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                      <p>No comments yet. Be the first to add one!</p>
                    </div>
                  ) : (
                    comments.map((comment, index) => (
                      <div key={index} className="border rounded-lg p-3 bg-white">
                        <div className="flex justify-between items-start mb-2">
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-sm">{comment.author}</span>
                            <Badge variant="outline" className="text-xs">{comment.role}</Badge>
                          </div>
                          <span className="text-xs text-gray-500">{comment.timestamp}</span>
                        </div>
                        <p className="text-sm">{comment.text}</p>
                      </div>
                    ))
                  )}
                </div>

                {/* Add Comment */}
                <div className="border-t pt-4 mt-4">
                  <div className="space-y-3">
                    <Label htmlFor="new-comment">{t("addCommentLabel")}</Label>
                    <textarea 
                      id="new-comment"
                      className="w-full p-3 border border-gray-300 rounded-md resize-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      value={newComment}
                      onChange={(e) => setNewComment(e.target.value)}
                      rows={3}
                    />
                    <p className="text-sm text-gray-600">{t("commentGuidance")}</p>
                    <div className="flex justify-end space-x-2">
                      <Button variant="outline" size="sm" onClick={() => {
                        setShowCommentsModal(false);
                        setNewComment("");
                      }}>
                        Cancel
                      </Button>
                      <Button 
                        size="sm"
                        onClick={() => {
                          if (newComment.trim()) {
                            const newCommentObj = {
                              text: newComment,
                              author: user?.username || "Current User",
                              role: user?.role || "User",
                              timestamp: "Just now"
                            };
                            setComments(prev => [newCommentObj, ...prev]);
                            toast({
                              title: "Success",
                              description: "Comment added successfully",
                            });
                            setNewComment("");
                          } else {
                            toast({
                              title: "Error",
                              description: "Please enter a comment",
                              variant: "destructive"
                            });
                          }
                        }}
                        disabled={!newComment.trim()}
                      >
                        Add Comment
                      </Button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Add Type Modal */}
      <Dialog open={showAddTypeModal} onOpenChange={setShowAddTypeModal}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Add New Feedback Type</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="type-name">Type Name</Label>
              <Input
                id="type-name"
                value={newTypeName}
                onChange={(e) => setNewTypeName(e.target.value)}
              />
              <p className="text-sm text-gray-600">{t("typeNameGuidance")}</p>
            </div>
          </div>
          <div className="flex justify-end space-x-3 pt-4">
            <Button variant="outline" onClick={() => {
              setShowAddTypeModal(false);
              setNewTypeName("");
            }}>
              Cancel
            </Button>
            <Button onClick={async () => {
              if (newTypeName.trim()) {
                try {
                  await apiRequest('POST', '/api/feedback-types', {
                    name: newTypeName,
                    displayName: newTypeName
                  });

                  queryClient.invalidateQueries({ queryKey: ["/api/feedback-types"] });

                  toast({
                    title: "Success",
                    description: `Feedback type "${newTypeName}" added successfully`,
                  });
                  setNewTypeName("");
                  setShowAddTypeModal(false);
                } catch (error) {
                  toast({
                    title: "Error",
                    description: "Failed to add feedback type",
                    variant: "destructive"
                  });
                }
              }
            }}>
              Add Type
            </Button>
          </div>
        </DialogContent>
      </Dialog>


    </div>
    </DashboardLayout>
  );
}

