        permissions: JSON.stringify({
          canViewUsers: true,
          canEditUsers: true,
          canDeleteUsers: false,
          canViewTodos: true,
          canEditTodos: true,
          canViewInterviews: true,
          canEditInterviews: true,
          canViewReports: true,
          canManageNotifications: false
        })
      },
      {
