    });
  };

  const clearEmployeeCountForm = () => {
    setEmployeeCountData({
      count1: "",
      count2: "",
      count3: "",
      count4: "",
      count5: "",
      count6: "",
    });
  };

  const clearYesterdayProductionForm = () => {
    setYesterdayProductionData({
      prod1: "",
      prod2: "",
      prod3: "",
      prod4: "",
      prod5: "",
      prod6: "",
    });
  };

  const clearYesterdayLoadingForm = () => {
    setYesterdayLoadingData({
      load1: "",
      load2: "",
      load3: "",
