import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { useAuth } from "@/hooks/use-auth";
import { useToast } from "@/hooks/use-toast";
import { authenticatedRequest } from "@/lib/auth";
import { queryClient } from "@/lib/queryClient";
import { motion, AnimatePresence } from "framer-motion";
import {
  Bell,
  Calendar,
  Clock,
  CheckCircle2,
  X,
  Filter,
  RefreshCw,
  AlertCircle,
  Plus,
} from "lucide-react";

interface Reminder {
  id: number;
  todoItemId: number;
  reminderDate: string;
  message?: string;
  title?: string;
  itemText?: string;
  itemData?: any;
  isCompleted: boolean;
  createdById: number;
  createdAt: string;
}

export default function RemindersPage() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { toast } = useToast();
  const [filterType, setFilterType] = useState<"all" | "today" | "upcoming" | "overdue">("today");
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [newReminderDate, setNewReminderDate] = useState("");
  const [newReminderMessage, setNewReminderMessage] = useState("");
  const [newReminderTitle, setNewReminderTitle] = useState("");

  // Fetch all reminders
  const { data: remindersData, isLoading, refetch: refetchReminders } = useQuery({
    queryKey: ["/api/reminders"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/reminders");
      return response.json();
    },
    enabled: !!user, // Only fetch when user is authenticated
    staleTime: 0, // Always consider data stale to ensure fresh data
    refetchOnWindowFocus: true,
  });

  // Fetch today's reminders
  const { data: todayRemindersData, refetch: refetchTodayReminders } = useQuery({
    queryKey: ["/api/reminders/today"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/reminders/today");
      return response.json();
    },
    enabled: !!user, // Only fetch when user is authenticated
    staleTime: 0, // Always consider data stale to ensure fresh data
    refetchOnWindowFocus: true,
  });

  // Update reminder mutation
  const updateReminderMutation = useMutation({
    mutationFn: async (data: { id: number; isCompleted: boolean }) => {
      const response = await authenticatedRequest("PATCH", `/api/reminders/${data.id}`, { isCompleted: data.isCompleted });
      return response.json();
    },
    onSuccess: async () => {
      await refetchReminders();
      await refetchTodayReminders();
      toast({
        title: "Success",
        description: "Reminder updated successfully!",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update reminder",
        variant: "destructive",
      });
    },
  });

  // Delete reminder mutation
  const deleteReminderMutation = useMutation({
    mutationFn: async (id: number) => {
      const response = await authenticatedRequest("DELETE", `/api/reminders/${id}`);
      return response.json();
    },
    onSuccess: async () => {
      await refetchReminders();
      await refetchTodayReminders();
      toast({
        title: "Success",
        description: "Reminder deleted successfully!",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete reminder",
        variant: "destructive",
      });
    },
  });

  // Create reminder mutation
  const createReminderMutation = useMutation({
    mutationFn: async (data: { reminderDate: string; message?: string; title?: string; itemText?: string }) => {
      const response = await authenticatedRequest("POST", "/api/reminders", {
        reminderDate: data.reminderDate,
        message: data.message,
        title: data.title,
        itemText: data.itemText,
        todoItemId: null,
      });
      return response.json();
    },
    onSuccess: async () => {
      // Force refresh all reminder queries
      await queryClient.invalidateQueries({ queryKey: ["/api/reminders"] });
      await queryClient.invalidateQueries({ queryKey: ["/api/reminders/today"] });

      // Also refetch to ensure immediate update
      await queryClient.refetchQueries({ queryKey: ["/api/reminders"] });
      await queryClient.refetchQueries({ queryKey: ["/api/reminders/today"] });

      setShowCreateDialog(false);
      setNewReminderDate("");
      setNewReminderMessage("");
      setNewReminderTitle("");
      toast({
        title: "Success",
        description: "Reminder created successfully!",
      });
    },
    onError: (error: any) => {
      console.error("Create reminder error:", error);
      toast({
        title: "Error",
        description: error.message || "Failed to create reminder",
        variant: "destructive",
      });
    },
  });

  const reminders: Reminder[] = remindersData?.reminders || [];
  const todayReminders: Reminder[] = todayRemindersData?.reminders || [];

  // Filter reminders based on type
  const filterReminders = () => {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    switch (filterType) {
      case "today":
        // Today includes all reminders from start of today to end of today
        return reminders.filter(reminder => {
          const reminderDate = new Date(reminder.reminderDate);
          return reminderDate >= today && reminderDate < tomorrow;
        });
      case "upcoming":
        return reminders.filter(reminder => {
          const reminderDate = new Date(reminder.reminderDate);
          return reminderDate >= tomorrow && !reminder.isCompleted;
        });
      case "overdue":
        return reminders.filter(reminder => {
          const reminderDate = new Date(reminder.reminderDate);
          return reminderDate < now && !reminder.isCompleted;
        });
      case "all":
      default:
        return reminders;
    }
  };

  const filteredReminders = filterReminders();

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    // Format date in local timezone
    const dateStr = date.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: '2-digit', 
      day: '2-digit' 
    });
    const timeStr = date.toLocaleTimeString('en-US', { 
      hour: '2-digit', 
      minute: '2-digit',
      hour12: true 
    });
    return `${dateStr} ${timeStr}`;
  };

  const isOverdue = (dateString: string) => {
    const now = new Date();
    const reminderDate = new Date(dateString);
    // A reminder is overdue if it's in the past and not completed
    return reminderDate < now;
  };

  const handleToggleComplete = (id: number, isCompleted: boolean) => {
    updateReminderMutation.mutate({ id, isCompleted: !isCompleted });
  };

  const handleDeleteReminder = (id: number) => {
    if (window.confirm("Are you sure you want to delete this reminder?")) {
      deleteReminderMutation.mutate(id);
    }
  };

  const handleCreateReminder = () => {
    if (!newReminderDate.trim() || (!newReminderMessage.trim() && !newReminderTitle.trim())) {
      toast({
        title: "Error",
        description: "Please fill in date and either title or message",
        variant: "destructive",
      });
      return;
    }

    // The datetime-local input gives us a string like "2025-10-05T11:24"
    // We need to treat this as local time, not UTC
    // Create a date object that preserves the local timezone
    const localDate = new Date(newReminderDate);

    // Convert to ISO string (this will be in UTC)
    const reminderDateTime = localDate.toISOString();

    createReminderMutation.mutate({
      reminderDate: reminderDateTime,
      message: newReminderMessage.trim() || undefined,
      title: newReminderTitle.trim() || undefined,
      itemText: newReminderTitle.trim() || newReminderMessage.trim() || undefined,
    });
  };

  // Helper function to get current datetime for input default
  const getCurrentDateTime = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    return `${year}-${month}-${day}T${hours}:${minutes}`;
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <Card className="bg-gradient-to-r from-amber-50 to-orange-50 border-amber-200">
          <CardHeader>
            <CardTitle className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-lg bg-amber-600 flex items-center justify-center">
                <Bell className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">{t("reminders")}</h1>
                <p className="text-sm text-gray-600 mt-1">{t("manageRemindersNotifications")}</p>
              </div>
            </CardTitle>
          </CardHeader>
          <CardContent>
            {/* Filter Controls */}
            <div className="flex gap-2 mb-4 flex-wrap">
              <Button
                variant={filterType === "today" ? "default" : "outline"}
                size="sm"
                onClick={() => setFilterType("today")}
                className="flex items-center gap-2"
                data-testid="filter-today"
              >
                <Calendar className="w-4 h-4" />
                {t("today")} ({todayReminders.length})
              </Button>
              <Button
                variant={filterType === "upcoming" ? "default" : "outline"}
                size="sm"
                onClick={() => setFilterType("upcoming")}
                className="flex items-center gap-2"
                data-testid="filter-upcoming"
              >
                <Clock className="w-4 h-4" />
                {t("upcomingReminders")}
              </Button>
              <Button
                variant={filterType === "overdue" ? "default" : "outline"}
                size="sm"
                onClick={() => setFilterType("overdue")}
                className="flex items-center gap-2"
                data-testid="filter-overdue"
              >
                <AlertCircle className="w-4 h-4" />
                {t("overdueReminders")}
              </Button>
              <Button
                variant={filterType === "all" ? "default" : "outline"}
                size="sm"
                onClick={() => setFilterType("all")}
                className="flex items-center gap-2"
                data-testid="filter-all"
              >
                <Filter className="w-4 h-4" />
                All ({reminders.length})
              </Button>

              <div className="flex gap-2 ml-auto">
                <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
                  <DialogTrigger asChild>
                    <Button
                      size="sm"
                      className="flex items-center gap-2 bg-green-600 hover:bg-green-700"
                      data-testid="button-create-reminder"
                    >
                      <Plus className="w-4 h-4" />
                      Create Reminder
                    </Button>
                  </DialogTrigger>
                  <DialogContent className="sm:max-w-md">
                    <DialogHeader>
                      <DialogTitle>Create New Reminder</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4">
                      <div>
                        <Label htmlFor="reminderTitle">Title</Label>
                        <Input
                          id="reminderTitle"
                          value={newReminderTitle}
                          onChange={(e) => setNewReminderTitle(e.target.value)}
                          data-testid="input-reminder-title"
                        />
                      </div>
                      <div>
                        <Label htmlFor="reminderDate">Date & Time</Label>
                        <Input
                          id="reminderDate"
                          type="datetime-local"
                          value={newReminderDate}
                          onChange={(e) => setNewReminderDate(e.target.value)}
                          min={getCurrentDateTime()}
                          data-testid="input-reminder-date"
                          required
                        />
                      </div>
                      <div>
                        <Label htmlFor="reminderMessage">Message (optional)</Label>
                        <Textarea
                          id="reminderMessage"
                          value={newReminderMessage}
                          onChange={(e) => setNewReminderMessage(e.target.value)}
                          rows={3}
                          data-testid="input-reminder-message"
                        />
                      </div>
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="outline"
                          onClick={() => setShowCreateDialog(false)}
                          data-testid="button-cancel-reminder"
                        >
                          Cancel
                        </Button>
                        <Button
                          onClick={handleCreateReminder}
                          disabled={createReminderMutation.isPending}
                          data-testid="button-save-reminder"
                        >
                          {createReminderMutation.isPending ? "Creating..." : "Create Reminder"}
                        </Button>
                      </div>
                    </div>
                  </DialogContent>
                </Dialog>

                <Button
                  variant="outline"
                  size="sm"
                  onClick={async () => {
                    await refetchReminders();
                    await refetchTodayReminders();
                    toast({
                      title: "Success",
                      description: "Reminders refreshed!",
                    });
                  }}
                  data-testid="button-refresh"
                >
                  <RefreshCw className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Reminders List */}
        {isLoading ? (
          <Card>
            <CardContent className="p-6">
              <div className="text-center">
                <RefreshCw className="w-8 h-8 animate-spin text-gray-400 mx-auto mb-2" />
                <p className="text-gray-600">Loading reminders...</p>
              </div>
            </CardContent>
          </Card>
        ) : filteredReminders.length === 0 ? (
          <Card>
            <CardContent className="p-6">
              <div className="text-center">
                <Bell className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-gray-600 mb-2">No Reminders Found</h3>
                <p className="text-gray-500">
                  {filterType === "today" 
                    ? "No reminders scheduled for today" 
                    : `No ${filterType} reminders to display`}
                </p>
              </div>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-4">
            <AnimatePresence>
              {filteredReminders.map((reminder) => (
                <motion.div
                  key={reminder.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="group"
                >
                  <Card className={`${
                    reminder.isCompleted 
                      ? 'bg-green-50 border-green-200' 
                      : isOverdue(reminder.reminderDate) 
                        ? 'bg-red-50 border-red-200' 
                        : 'bg-white border-gray-200'
                  } hover:shadow-md transition-shadow`}>
                    <CardContent className="p-4">
                      <div className="flex items-start gap-3">
                        {/* Completion Toggle */}
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => handleToggleComplete(reminder.id, reminder.isCompleted)}
                          className="flex-shrink-0 p-1"
                        >
                          {reminder.isCompleted ? (
                            <CheckCircle2 className="w-5 h-5 text-green-600" />
                          ) : (
                            <div className="w-5 h-5 rounded-full border-2 border-gray-400 hover:border-blue-500" />
                          )}
                        </Button>

                        {/* Content */}
                        <div className="flex-1">
                          <div className="flex items-start justify-between">
                            <div>
                              <div className="flex items-center gap-2 mb-1">
                                <Badge variant={
                                  reminder.isCompleted 
                                    ? "secondary" 
                                    : isOverdue(reminder.reminderDate) && !reminder.isCompleted
                                      ? "destructive" 
                                      : "default"
                                }>
                                  {reminder.isCompleted 
                                    ? "Completed" 
                                    : isOverdue(reminder.reminderDate) && !reminder.isCompleted
                                      ? "Overdue" 
                                      : "Pending"}
                                </Badge>
                                {isOverdue(reminder.reminderDate) && !reminder.isCompleted && (
                                  <AlertCircle className="w-4 h-4 text-red-500" />
                                )}
                              </div>

                              <div className="flex items-center gap-2 text-sm text-gray-600 mb-2">
                                <Clock className="w-4 h-4" />
                                <span className={reminder.isCompleted ? 'line-through' : ''}>
                                  {formatDate(reminder.reminderDate)}
                                </span>
                              </div>

                              {/* Item Content */}
                              {reminder.itemText && (
                                <div className={`p-3 bg-gray-50 rounded-lg border-l-4 border-blue-500 mb-2 ${reminder.isCompleted ? 'opacity-60' : ''}`}>
                                  <p className="text-sm font-medium text-gray-900 mb-1">Task Item:</p>
                                  <p className={`text-sm text-gray-800 ${reminder.isCompleted ? 'line-through' : ''}`}>
                                    "{reminder.itemText}"
                                  </p>
                                  {reminder.itemData?.list && (
                                    <div className="mt-2 text-xs text-gray-600">
                                      <span className="inline-flex items-center gap-1">
                                        <span>From list:</span>
                                        <span className="font-medium">{reminder.itemData.list.title}</span>
                                        <Badge variant="outline" className="text-xs">
                                          {reminder.itemData.list.priority}
                                        </Badge>
                                      </span>
                                    </div>
                                  )}
                                </div>
                              )}

                              {reminder.message && (
                                <p className={`text-sm text-gray-800 ${reminder.isCompleted ? 'line-through' : ''}`}>
                                  {reminder.message}
                                </p>
                              )}
                            </div>

                            {/* Actions */}
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => handleDeleteReminder(reminder.id)}
                                className="text-red-500 hover:text-red-700 hover:bg-red-50 p-1"
                                title="Delete reminder"
                              >
                                <X className="w-4 h-4" />
                              </Button>
                            </div>
                          </div>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                </motion.div>
              ))}
            </AnimatePresence>
          </div>
        )}
      </div>
    </DashboardLayout>
  );
}

