import { useState, useEffect } from "react";
import StructuredNavigation from "@/components/navigation/structured-navigation";
import { Menu, X } from "lucide-react";
import { Button } from "@/components/ui/button";

export default function Sidebar() {
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const checkScreenSize = () => {
      const mobile = window.innerWidth < 1024;
      setIsMobile(mobile);
      if (!mobile) {
        setIsOpen(false);
      }
    };

    checkScreenSize();
    window.addEventListener('resize', checkScreenSize);
    return () => window.removeEventListener('resize', checkScreenSize);
  }, []);

  // Mobile sidebar overlay
  if (isMobile) {
    return (
      <>
        {/* Mobile menu trigger */}
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setIsOpen(!isOpen)}
          className="fixed top-4 left-4 z-50 lg:hidden bg-white shadow-lg border border-red-200 hover:bg-red-50 animate-pulse-hover"
        >
          {isOpen ? <X className="h-5 w-5 text-red-600 menu-icon" /> : <Menu className="h-5 w-5 text-red-600 menu-icon" />}
        </Button>

        {/* Mobile overlay */}
        {isOpen && (
          <div 
            className="fixed inset-0 bg-black/50 z-40 lg:hidden"
            onClick={() => setIsOpen(false)}
          />
        )}

        {/* Mobile sidebar */}
        <div className={`
          fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-red-200 shadow-2xl
          transform transition-all duration-300 ease-in-out lg:hidden animate-slide-in
          ${isOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
          <div className="flex h-full flex-col overflow-y-auto px-6 pb-4 pt-16">
            <div className="animate-fade-in">
              <StructuredNavigation />
            </div>
          </div>
        </div>
      </>
    );
  }

  // Desktop sidebar
  return (
    <div className={`
      hidden lg:fixed lg:inset-y-0 lg:z-50 lg:flex lg:flex-col transition-all duration-300 animate-slide-in
      ${isCollapsed ? 'lg:w-16' : 'lg:w-72'}
    `}>
      <div className="flex grow flex-col overflow-hidden bg-white border-r border-red-200 shadow-lg">
        {/* Sidebar header with toggle */}
        <div className="flex items-center justify-between p-4 pt-20 border-b border-red-200 bg-gradient-to-r from-red-50 to-white">
          {!isCollapsed && (
            <h2 className="text-lg font-semibold text-red-800 animate-fade-in">Navigation</h2>
          )}
          <div className="flex items-center space-x-2">
            {/* Animated Menu Handle */}
            <div className="menu-handle p-2 rounded-lg bg-red-100 hover:bg-red-200 cursor-pointer">
              <div className="menu-handle-grip">
                <div className="grip-line"></div>
                <div className="grip-line"></div>
                <div className="grip-line"></div>
              </div>
            </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setIsCollapsed(!isCollapsed)}
              className="p-2 hover:bg-red-100 animate-bounce-hover menu-handle"
            >
              <Menu className="h-4 w-4 text-red-600 menu-icon" />
            </Button>
          </div>
        </div>

        {/* Navigation content */}
        <div className="flex-1 overflow-hidden px-3 pb-4 bg-white slide-menu-container">
          <div className="h-full overflow-y-auto overflow-x-hidden scrollbar-hide hover:scrollbar-show">
            <div className="animate-fade-in">
              <StructuredNavigation className={isCollapsed ? "space-y-1" : ""} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

client/src/components/ui/modern-button.t.content:
import { forwardRef } from "react";
import { Button, ButtonProps } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface ModernButtonProps extends ButtonProps {
  gradient?: boolean;
  shadow?: boolean;
}

const ModernButton = forwardRef<HTMLButtonElement, ModernButtonProps>(
  ({ className, variant = "default", gradient = false, shadow = true, ...props }, ref) => {
    const getVariantClasses = () => {
      switch (variant) {
        case "default":
          return gradient
            ? "bg-gradient-to-r from-dashboard-primary to-dashboard-primary/80 hover:from-dashboard-primary/90 hover:to-dashboard-primary/70 text-white"
            : "bg-dashboard-primary hover:bg-dashboard-primary/90 text-white";
        case "secondary":
          return "bg-dashboard-secondary hover:bg-dashboard-secondary/90 text-white";
        case "accent":
          return gradient
            ? "bg-gradient-to-r from-dashboard-accent to-dashboard-accent/80 hover:from-dashboard-accent/90 hover:to-dashboard-accent/70 text-white"
            : "bg-dashboard-accent hover:bg-dashboard-accent/90 text-white";
        case "destructive":
          return "bg-dashboard-error hover:bg-dashboard-error/90 text-white";
        case "outline":
          return "border-2 border-dashboard-primary/20 hover:border-dashboard-primary/50 hover:bg-dashboard-primary/5 text-dashboard-text-light dark:text-dashboard-text-dark";
        case "ghost":
          return "hover:bg-dashboard-primary/10 text-dashboard-text-light dark:text-dashboard-text-dark hover:text-dashboard-primary";
        default:
          return "";
      }
    };

    const shadowClasses = shadow ? "shadow-lg hover:shadow-xl transition-shadow duration-200" : "";

    return (
      <Button
        className={cn(
          "font-medium py-2 px-4 rounded-xl transition-all duration-200",
          getVariantClasses(),
          shadowClasses,
          className
        )}
        variant="ghost" // Reset base variant to avoid conflicts
        ref={ref}
        {...props}
      />
    );
  }
);

ModernButton.displayName = "ModernButton";

export { ModernButton };

