import { useState } from "react";
import { Link, useLocation } from "wouter";
import { 
  Home, 
  Users, 
  ChevronDown,
  ChevronRight,
  Zap,
  Building2,
  Activity,
  Bell,
  HardDrive,
  LucideIcon,
  ListTodo,
  Briefcase,
  TrendingUp,
  Settings,
  Clock,
  Users2,
  UserPlus,
  MessageCircle,
  MessageSquare,
  Archive,
  Lock,
  FileText,
  Eye,
  Layers,
  Radio,
  Play,
  TestTube,
  Wrench,
  ClipboardList,
  Send,
  LayoutDashboard,
  Shield,
  Database
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useAuth } from "@/hooks/use-auth";
import { useTranslation } from "react-i18next";
import { PAGE_PERMISSIONS } from "@shared/schema";
import { MENU_PARTITIONS } from "@/lib/menu-partitions";

const partitionIconMap: Record<string, LucideIcon> = {
  ListTodo,
  ClipboardList,
  Users,
  Briefcase,
  TrendingUp,
  Settings,
};

const itemIconMap: Record<string, LucideIcon> = {
  Zap,
  Clock,
  Activity,
  Users,
  Users2,
  UserPlus,
  Building2,
  MessageCircle,
  MessageSquare,
  Archive,
  Lock,
  FileText,
  Database,
  Eye,
  Layers,
  Radio,
  Bell,
  HardDrive,
  Play,
  TestTube,
  Wrench,
  Send,
};

const getPartitionIcon = (iconName: string): LucideIcon => {
  return partitionIconMap[iconName] || ListTodo;
};

const getItemIcon = (iconName?: string): LucideIcon | null => {
  if (!iconName) return null;
  return itemIconMap[iconName] || null;
};

interface SidebarProps {
  isCollapsed?: boolean;
  onToggle?: () => void;
  className?: string;
}

export function DashboardSidebar({ isCollapsed = false, onToggle, className }: SidebarProps) {
  const [location] = useLocation();
  const { user } = useAuth();
  const { t } = useTranslation();
  const [expandedPartitions, setExpandedPartitions] = useState<Set<string>>(new Set(['Task Management']));

  const togglePartition = (partitionTitle: string) => {
    const newExpanded = new Set(expandedPartitions);
    if (newExpanded.has(partitionTitle)) {
      newExpanded.delete(partitionTitle);
    } else {
      newExpanded.add(partitionTitle);
    }
    setExpandedPartitions(newExpanded);
  };

  const isAdmin = user?.role === 'admin';

  const hasPermission = (href: string): boolean => {
    if (isAdmin) return true;

    const permissionKey = PAGE_PERMISSIONS[href as keyof typeof PAGE_PERMISSIONS];
    if (!permissionKey) return false;

    const permissions = user?.permissions as Record<string, boolean> | undefined;
    return permissions?.[permissionKey] === true;
  };

  const getPartitionItems = () => {
    return MENU_PARTITIONS.map(partition => ({
      ...partition,
      items: partition.items.filter(item => hasPermission(item.path))
    })).filter(partition => partition.items.length > 0);
  };

  const partitionItems = getPartitionItems();

  const isActive = (href: string) => {
    if (href === "/") {
      return location === "/";
    }
    return location.startsWith(href);
  };

  const dashboardActive = isActive("/");

  return (
    <aside className={cn(
      "flex flex-col h-full trello-sidebar transition-all duration-200",
      isCollapsed ? "w-16" : "w-64",
      className
    )}>
      <div className="flex items-center gap-3 px-4 py-4 border-b border-white/10">
        {!isCollapsed ? (
          <>
            <div className="w-8 h-8 rounded bg-gradient-to-br from-primary to-blue-400 flex items-center justify-center">
              <Building2 className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-base tracking-tight">Shyaw Admin</span>
          </>
        ) : (
          <div className="w-8 h-8 rounded bg-gradient-to-br from-primary to-blue-400 flex items-center justify-center mx-auto">
            <Building2 className="w-5 h-5 text-white" />
          </div>
        )}
      </div>

      <nav className="flex-1 px-3 py-4 space-y-1 overflow-y-auto scrollbar-hide">
        <Link href="/">
          <div
            className={cn(
              "trello-sidebar-item",
              dashboardActive && "trello-sidebar-item-active bg-white/10"
            )}
            data-testid="link-dashboard"
          >
            <LayoutDashboard className="w-5 h-5 flex-shrink-0" />
            {!isCollapsed && <span>Dashboard</span>}
          </div>
        </Link>

        <div className="h-px bg-white/10 my-3" />

        {partitionItems.map((partition) => {
          const isExpanded = expandedPartitions.has(partition.title);
          const PartitionIcon = getPartitionIcon(partition.iconName);

          return (
            <div key={partition.title} className="space-y-0.5">
              <button
                onClick={() => !isCollapsed && togglePartition(partition.title)}
                className={cn(
                  "w-full trello-sidebar-item group",
                  isExpanded && "text-white"
                )}
                title={isCollapsed ? partition.title : undefined}
                data-testid={`btn-partition-${partition.title.toLowerCase().replace(/\s+/g, '-')}`}
              >
                <PartitionIcon className="w-5 h-5 flex-shrink-0 opacity-80" />
                {!isCollapsed && (
                  <>
                    <span className="flex-1 text-left text-sm">{t(partition.titleKey)}</span>
                    <ChevronDown 
                      className={cn(
                        "w-4 h-4 opacity-60 transition-transform duration-200",
                        isExpanded && "rotate-180"
                      )} 
                    />
                  </>
                )}
              </button>

              {isExpanded && !isCollapsed && (
                <div className="ml-2 pl-4 border-l border-white/10 space-y-0.5 animate-fade-in">
                  {partition.items.map((item) => {
                    const active = isActive(item.path);
                    const ItemIcon = getItemIcon(item.iconName);

                    return (
                      <Link key={item.path} href={item.path}>
                        <div
                          className={cn(
                            "flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm transition-all duration-150 cursor-pointer",
                            active 
                              ? "bg-primary text-white font-medium" 
                              : "text-white/70 hover:text-white hover:bg-white/10"
                          )}
                          data-testid={`link-${item.path.replace(/\//g, '-').slice(1) || 'home'}`}
                        >
                          {ItemIcon && (
                            <ItemIcon className={cn("w-4 h-4 flex-shrink-0", active ? "text-white" : "opacity-70")} />
                          )}
                          <span>{t(item.labelKey)}</span>
                        </div>
                      </Link>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}

        {isAdmin && (
          <>
            <div className="h-px bg-white/10 my-3" />

            {!isCollapsed && (
              <div className="px-3 py-2">
                <span className="text-[10px] font-semibold uppercase tracking-wider text-white/40">
                  Administration
                </span>
              </div>
            )}

            <Link href="/page-access-management">
              <div
                className={cn(
                  "trello-sidebar-item",
                  isActive("/page-access-management") && "trello-sidebar-item-active bg-white/10"
                )}
                data-testid="link-page-access"
              >
                <Shield className="w-5 h-5 flex-shrink-0 opacity-80" />
                {!isCollapsed && <span className="text-sm">Page Access</span>}
              </div>
            </Link>

            <Link href="/backup-restore">
              <div
                className={cn(
                  "trello-sidebar-item",
                  isActive("/backup-restore") && "trello-sidebar-item-active bg-white/10"
                )}
                data-testid="link-backup-restore"
              >
                <HardDrive className="w-5 h-5 flex-shrink-0 opacity-80" />
                {!isCollapsed && <span className="text-sm">Backup & Restore</span>}
              </div>
            </Link>
          </>
        )}
      </nav>

      {!isCollapsed && user && (
        <div className="p-3 border-t border-white/10">
          <div className="flex items-center gap-3 px-3 py-2.5 rounded-lg bg-white/5 hover:bg-white/10 transition-colors cursor-pointer">
            <div className="trello-avatar trello-avatar-sm bg-primary/80">
              {user.username?.charAt(0).toUpperCase()}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium truncate">{user.username}</p>
              <p className="text-xs text-white/50 capitalize">{user.role}</p>
            </div>
          </div>
        </div>
      )}
    </aside>
  );
}

client/src/pages/users.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { DashboardLayout } from "@/components/layout/dashboard-layout";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { authenticatedRequest } from "@/lib/auth";
import { queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Plus, Edit, Trash, User, MessageSquare } from "lucide-react";
import AddUserModal from "@/components/modals/add-user-modal";
import { HelpTooltip, FeatureTooltip, RoleTooltip, StatusTooltip, ActionTooltip } from "@/components/ui/help-tooltip";
import { useTranslation } from "react-i18next";

export default function UsersPage() {
  const { t } = useTranslation();
  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingUser, setEditingUser] = useState<any>(null);
  const [userToDelete, setUserToDelete] = useState<any>(null);
  const { toast } = useToast();

  const { data: usersData, isLoading } = useQuery({
    queryKey: ["/api/users"],
    queryFn: async () => {
      const response = await authenticatedRequest("GET", "/api/users");
      return await response.json();
    },
  });

  const updateUserMutation = useMutation({
    mutationFn: async ({ id, updates }: { id: number; updates: any }) => {
      const response = await authenticatedRequest("PATCH", `/api/users/${id}`, updates);
      return await response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users"] });
      setEditingUser(null);
      toast({
        title: "Success",
        description: "User updated successfully",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update user",
        variant: "destructive",
      });
    },
  });

  const deleteUserMutation = useMutation({
    mutationFn: async (id: number) => {
      const response = await authenticatedRequest("DELETE", `/api/users/${id}`);
      if (!response.ok) {
        throw new Error("Failed to delete user");
      }
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users"] });
      setUserToDelete(null);
      toast({
        title: "Success",
        description: "User deleted successfully",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete user",
        variant: "destructive",
      });
    },
  });

  const users = usersData?.users || [];

  const filteredUsers = users.filter((user: any) => {
    const matchesSearch = user.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.username.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesRole = roleFilter === "all" || user.role === roleFilter;
    const matchesStatus = statusFilter === "all" || user.status === statusFilter;

    return matchesSearch && matchesRole && matchesStatus;
  });

  const getRoleBadgeColor = (role: string) => {
    switch (role) {
      case "admin":
        return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300";
      case "manager":
        return "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300";
      case "security":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300";
      default:
        return "bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300";
    }
  };

  const getStatusBadgeColor = (status: string) => {
    switch (status) {
      case "active":
        return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300";
      case "inactive":
        return "bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300";
      case "pending":
        return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300";
      default:
        return "bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300";
    }
  };

  const handleApproveUser = (userId: number) => {
    updateUserMutation.mutate({
      id: userId,
      updates: { status: "active" }
    });
  };

  const handleRejectUser = (userId: number) => {
    updateUserMutation.mutate({
      id: userId,
      updates: { status: "inactive" }
    });
  };

  const handleEditUser = (user: any) => {
    setEditingUser({...user, password: ''}); // Clear password field for new entry
  };

  const handleDeleteUser = (user: any) => {
    setUserToDelete(user);
  };

  const handleUpdateUser = () => {
    if (!editingUser) return;

    const updates: any = {
      firstName: editingUser.firstName,
      lastName: editingUser.lastName,
      email: editingUser.email,
      role: editingUser.role,
      status: editingUser.status,
      managerId: editingUser.managerId || null,
      comments: editingUser.comments || ''
    };

    // Include password only if it's provided (not empty)
    if (editingUser.password && editingUser.password.trim() !== '') {
      updates.password = editingUser.password;
    }

    updateUserMutation.mutate({
      id: editingUser.id,
      updates: updates
    });
  };

  const confirmDeleteUser = () => {
    if (!userToDelete) return;
    deleteUserMutation.mutate(userToDelete.id);
  };

  if (isLoading) {
    return (
      <DashboardLayout>
        <div className="animate-pulse">
          <div className="mb-8">
            <div className="h-8 bg-dashboard-secondary/20 rounded w-64 mb-2"></div>
            <div className="h-4 bg-dashboard-secondary/20 rounded w-96"></div>
          </div>
          <div className="h-96 bg-dashboard-secondary/20 rounded-xl"></div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="mb-8">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div>
              <h2 className="text-3xl font-bold text-dashboard-text-light dark:text-dashboard-text-dark mb-2">{t("employeeManagement")}</h2>
              <p className="text-dashboard-secondary dark:text-dashboard-text-dark/70">{t("manageEmployeeAccountsDesc")}</p>
            </div>
            <HelpTooltip
              content="This page allows you to manage all internal employees. You can view, search, filter, add, edit, and manage employee roles and statuses. Use the filters to find specific employees and the action buttons to perform management tasks."
              type="info"
            />
          </div>
          <FeatureTooltip
            feature="Add New Employee"
            description="Create a new employee account with role assignment and access permissions. Required information includes personal details, contact info, and role selection."
            shortcut="Click to open form"
          >
            <Button onClick={() => setShowAddModal(true)} className="bg-dashboard-primary hover:bg-dashboard-primary/90">
              <Plus className="w-4 h-4 mr-2" />
{t("addEmployee")}
            </Button>
          </FeatureTooltip>
        </div>
      </div>

      {/* Filter Bar */}
      <Card className="mb-6">
        <CardContent className="pt-6">
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex-1 min-w-64">
              <FeatureTooltip
                feature="Employee Search"
                description="Search by employee name, email, or username. Results update in real-time as you type."
                shortcut="Type to search"
              >
                <Input
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  aria-label="Search employees"
                />
              </FeatureTooltip>
            </div>
            <HelpTooltip
              content="Filter employees by their assigned role. Each role has different access permissions and responsibilities within the system."
              type="tip"
            >
              <Select value={roleFilter} onValueChange={setRoleFilter}>
                <SelectTrigger className="w-32">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Roles</SelectItem>
                  <SelectItem value="admin">Admin</SelectItem>
                  <SelectItem value="manager">Manager</SelectItem>
                  <SelectItem value="security">Security</SelectItem>
                  <SelectItem value="office">Office</SelectItem>
                  <SelectItem value="secretary">Secretary</SelectItem>
                  <SelectItem value="office_team">Office Team</SelectItem>
                  <SelectItem value="employee">Employee</SelectItem>
                </SelectContent>
              </Select>
            </HelpTooltip>
            <StatusTooltip
              status="Filter Status"
              description="Filter employees by their account status"
              nextAction="Select status to filter"
            >
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-32">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="inactive">Inactive</SelectItem>
                  <SelectItem value="pending">Pending</SelectItem>
                </SelectContent>
              </Select>
            </StatusTooltip>
          </div>
        </CardContent>
      </Card>

      {/* Users Table */}
      <Card>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Employee</TableHead>
              <TableHead>Role</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Comments</TableHead>
              <TableHead>Last Active</TableHead>
              <TableHead>Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredUsers.map((user: any) => (
              <TableRow key={user.id}>
                <TableCell>
                  <div className="flex items-center space-x-3">
                    <Avatar>
                      <AvatarFallback>
                        <User className="w-4 h-4" />
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <div className="font-medium text-gray-900 dark:text-gray-100 flex items-center gap-2">
                        {user.firstName} {user.lastName}
                        {user.comments && user.comments.trim() !== '' && (
                          <TooltipProvider>
                            <Tooltip>
                              <TooltipTrigger asChild>
                                <MessageSquare className="w-4 h-4 text-blue-500 cursor-help" data-testid={`icon-comments-${user.id}`} />
                              </TooltipTrigger>
                              <TooltipContent className="max-w-xs bg-white dark:bg-gray-800 border dark:border-gray-700">
                                <p className="text-sm text-gray-900 dark:text-gray-100">{user.comments}</p>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        )}
                      </div>
                      <div className="text-sm text-gray-500 dark:text-gray-400">{user.email}</div>
                      <div className="text-xs text-gray-400 dark:text-gray-500">@{user.username}</div>
                    </div>
                  </div>
                </TableCell>
                <TableCell>
                  <RoleTooltip
                    role={user.role}
                    permissions={
                      user.role === "admin" 
                        ? ["Manage all users", "Access all data", "System settings", "Reports"] 
                        : user.role === "manager"
                        ? ["Manage employees", "View reports", "Approve interviews", "Data access"]
                        : ["View assigned tasks", "Submit interviews", "Basic operations"]
                    }
                  >
                    <Badge className={getRoleBadgeColor(user.role)}>
                      {user.role.charAt(0).toUpperCase() + user.role.slice(1)}
                    </Badge>
                  </RoleTooltip>
                </TableCell>
                <TableCell>
                  <StatusTooltip
                    status={user.status}
                    description={
                      user.status === "active" ? "Employee has full access to the system" :
                      user.status === "inactive" ? "Employee account is disabled" :
                      "Employee registration is awaiting approval"
                    }
                    nextAction={
                      user.status === "pending" ? "Review and approve/reject" :
                      user.status === "inactive" ? "Can be reactivated if needed" :
                      undefined
                    }
                  >
                    <Badge className={getStatusBadgeColor(user.status)}>
                      {user.status.charAt(0).toUpperCase() + user.status.slice(1)}
                    </Badge>
                  </StatusTooltip>
                </TableCell>
                <TableCell className="text-sm text-gray-600 dark:text-gray-400">
                  <div className="max-w-xs truncate">
                    {user.comments && user.comments.trim() !== '' ? (
                      <TooltipProvider>
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <span className="cursor-help">{user.comments}</span>
                          </TooltipTrigger>
                          <TooltipContent className="max-w-xs bg-white dark:bg-gray-800 border dark:border-gray-700">
                            <p className="text-sm text-gray-900 dark:text-gray-100 whitespace-normal">{user.comments}</p>
                          </TooltipContent>
                        </Tooltip>
                      </TooltipProvider>
                    ) : (
                      <span className="text-gray-400 italic">No comments</span>
                    )}
                  </div>
                </TableCell>
                <TableCell className="text-sm text-gray-600 dark:text-gray-400">
                  {user.lastActiveAt
                    ? new Date(user.lastActiveAt).toLocaleDateString()
                    : "Never"
                  }
                </TableCell>
                <TableCell>
                  <div className="flex items-center space-x-2">
                    {user.status === "pending" ? (
                      <>
                        <ActionTooltip
                          action="Approve Employee"
                          description="Grant access to the system and activate the employee account"
                        >
                          <Button
                            size="sm"
                            variant="outline"
                            className="text-green-600 hover:text-green-700"
                            onClick={() => handleApproveUser(user.id)}
                            disabled={updateUserMutation.isPending}
                          >
                            Approve
                          </Button>
                        </ActionTooltip>
                        <ActionTooltip
                          action="Reject Employee"
                          description="Deny access and mark the account as inactive"
                        >
                          <Button
                            size="sm"
                            variant="outline"
                            className="text-red-600 hover:text-red-700"
                            onClick={() => handleRejectUser(user.id)}
                            disabled={updateUserMutation.isPending}
                          >
                            Reject
                          </Button>
                        </ActionTooltip>
                      </>
                    ) : (
                      <>
                        <ActionTooltip
                          action="Edit Employee"
                          description="Modify employee information, role, and account settings"
                        >
                          <Button 
                            size="sm" 
                            variant="ghost"
                            onClick={() => handleEditUser(user)}
                            className="text-blue-600 hover:text-blue-700 hover:bg-blue-50 dark:hover:bg-blue-900/20"
                          >
                            <Edit className="w-4 h-4" />
                          </Button>
                        </ActionTooltip>
                        <ActionTooltip
                          action="Delete Employee"
                          description="Permanently remove employee account and all associated data"
                          danger={true}
                        >
                          <Button 
                            size="sm" 
                            variant="ghost" 
                            onClick={() => handleDeleteUser(user)}
                            className="text-red-600 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-900/20"
                          >
                            <Trash className="w-4 h-4" />
                          </Button>
                        </ActionTooltip>
                      </>
                    )}
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </Card>

      <AddUserModal open={showAddModal} onOpenChange={setShowAddModal} />

      {/* Edit User Modal */}
      <Dialog open={!!editingUser} onOpenChange={() => setEditingUser(null)}>
        <DialogContent className="bg-white dark:bg-gray-800 border dark:border-gray-700 max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-gray-900 dark:text-gray-100">Edit User</DialogTitle>
            <DialogDescription className="text-gray-600 dark:text-gray-400">
              Update user information and settings.
            </DialogDescription>
          </DialogHeader>

          {editingUser && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="firstName" className="text-gray-700 dark:text-gray-300">First Name</Label>
                  <Input
                    id="firstName"
                    value={editingUser.firstName}
                    onChange={(e) => setEditingUser({...editingUser, firstName: e.target.value})}
                    className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100"
                  />
                </div>
                <div>
                  <Label htmlFor="lastName" className="text-gray-700 dark:text-gray-300">Last Name</Label>
                  <Input
                    id="lastName"
                    value={editingUser.lastName}
                    onChange={(e) => setEditingUser({...editingUser, lastName: e.target.value})}
                    className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100"
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="email" className="text-gray-700 dark:text-gray-300">Email</Label>
                <Input
                  id="email"
                  type="email"
                  value={editingUser.email}
                  onChange={(e) => setEditingUser({...editingUser, email: e.target.value})}
                  className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100"
                />
              </div>

              <div>
                <Label htmlFor="newPassword" className="text-gray-700 dark:text-gray-300">New Password (optional)</Label>
                <Input
                  id="newPassword"
                  type="password"
                  value={editingUser.password || ''}
                  onChange={(e) => setEditingUser({...editingUser, password: e.target.value})}
                  className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100"
                />
                <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">Leave blank to keep current password</p>
              </div>

              <div>
                <Label htmlFor="role" className="text-gray-700 dark:text-gray-300">Role</Label>
                <Select 
                  value={editingUser.role} 
                  onValueChange={(value) => setEditingUser({...editingUser, role: value})}
                >
                  <SelectTrigger className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-white dark:bg-gray-800 border dark:border-gray-700">
                    <SelectItem value="admin">Admin</SelectItem>
                    <SelectItem value="manager">Manager</SelectItem>
                    <SelectItem value="security">Security</SelectItem>
                    <SelectItem value="secretary">Secretary</SelectItem>
                    <SelectItem value="office">Office</SelectItem>
                    <SelectItem value="office_team">Office Team</SelectItem>
                    <SelectItem value="employee">Employee</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label htmlFor="status" className="text-gray-700 dark:text-gray-300">Status</Label>
                <Select 
                  value={editingUser.status} 
                  onValueChange={(value) => setEditingUser({...editingUser, status: value})}
                >
                  <SelectTrigger className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-white dark:bg-gray-800 border dark:border-gray-700">
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                    <SelectItem value="pending">Pending</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label htmlFor="manager" className="text-gray-700 dark:text-gray-300">Manager</Label>
                <Select 
                  value={editingUser.managerId?.toString() || "none"} 
                  onValueChange={(value) => setEditingUser({...editingUser, managerId: value === "none" ? null : parseInt(value)})}
                >
                  <SelectTrigger className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100" data-testid="select-manager">
                    <SelectValue placeholder="Select manager" />
                  </SelectTrigger>
                  <SelectContent className="bg-white dark:bg-gray-800 border dark:border-gray-700">
                    <SelectItem value="none">No Manager</SelectItem>
                    {users
                      .filter((u: any) => u.id !== editingUser.id)
                      .map((user: any) => (
                        <SelectItem key={user.id} value={user.id.toString()}>
                          {user.firstName} {user.lastName} ({user.role})
                        </SelectItem>
                      ))
                    }
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label htmlFor="comments" className="text-gray-700 dark:text-gray-300">Comments</Label>
                <Textarea
                  id="comments"
                  value={editingUser.comments || ''}
                  onChange={(e) => setEditingUser({...editingUser, comments: e.target.value})}
                  className="bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100"
                  placeholder="Add notes or comments about this user..."
                  rows={3}
                  data-testid="textarea-comments"
                />
              </div>
            </div>
          )}

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setEditingUser(null)}
              className="border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700"
            >
              Cancel
            </Button>
            <Button 
              onClick={handleUpdateUser}
              disabled={updateUserMutation.isPending}
              className="bg-blue-600 hover:bg-blue-700 text-white"
            >
              {updateUserMutation.isPending ? "Updating..." : "Update User"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete User Modal */}
      <Dialog open={!!userToDelete} onOpenChange={() => setUserToDelete(null)}>
        <DialogContent className="bg-white dark:bg-gray-800 border dark:border-gray-700">
          <DialogHeader>
            <DialogTitle className="text-red-600 dark:text-red-400">Delete User</DialogTitle>
            <DialogDescription className="text-gray-600 dark:text-gray-400">
              Are you sure you want to delete this user? This action cannot be undone.
            </DialogDescription>
          </DialogHeader>

          {userToDelete && (
            <div className="bg-gray-50 dark:bg-gray-700 p-4 rounded-lg">
              <p className="text-gray-900 dark:text-gray-100 font-medium">
                {userToDelete.firstName} {userToDelete.lastName}
              </p>
              <p className="text-gray-600 dark:text-gray-400 text-sm">
                {userToDelete.email}
              </p>
              <p className="text-gray-500 dark:text-gray-500 text-xs">
                @{userToDelete.username}
              </p>
            </div>
          )}

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setUserToDelete(null)}
              className="border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700"
            >
              Cancel
            </Button>
            <Button 
              onClick={confirmDeleteUser}
              disabled={deleteUserMutation.isPending}
              className="bg-red-600 hover:bg-red-700 text-white"
            >
              {deleteUserMutation.isPending ? "Deleting..." : "Delete User"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
}

