      .select()
      .from(operationalData)
      .leftJoin(users, eq(operationalData.createdById, users.id))
      .orderBy(desc(operationalData.createdAt));

    return entries.map(entry => ({
      ...entry.operational_data,
      createdBy: entry.users!,
    }));
  }

  async deleteOperationalData(id: number): Promise<boolean> {
    const result = await db
      .delete(operationalData)
      .where(eq(operationalData.id, id));
    return (result.rowCount || 0) > 0;
  }

  async clearAllOperationalData(): Promise<boolean> {
    await db.delete(operationalData);
    return true;
  }

  async deleteArchivedItem(archiveId: number): Promise<boolean> {
    const result = await db
      .delete(archivedItems)
      .where(eq(archivedItems.id, archiveId));
    return (result.rowCount || 0) > 0;
  }

  async createWeeklyMeeting(data: any): Promise<any> {
    const result = await db.insert(weeklyMeetings).values(data).returning();
    return (result as any[])[0];
  }

  async getWeeklyMeetings(): Promise<any[]> {
    return await db.select().from(weeklyMeetings).orderBy(desc(weeklyMeetings.createdAt));
  }

  async getWeeklyMeeting(id: number): Promise<any> {
    const result = await db.select().from(weeklyMeetings).where(eq(weeklyMeetings.id, id));
    return (result as any[])[0];
  }

  async createWeeklyMeetingTask(data: any): Promise<any> {
    const dataWithDefaults = {
      ...data,
      createdById: data.createdById || 1,
    };
    const result = await db.insert(weeklyMeetingTasks).values(dataWithDefaults).returning();
    return (result as any[])[0];
  }

  async getWeeklyMeetingTasks(meetingId: number): Promise<any[]> {
    try {
      const tasks = await db.select().from(weeklyMeetingTasks).where(eq(weeklyMeetingTasks.meetingId, meetingId));
      return tasks;
    } catch (err) {
      console.error(`Failed to fetch tasks for meeting ${meetingId}:`, err);
      return [];
    }
  }

  async createTaskComment(taskId: number, authorId: number, comment: string, proofUrl?: string): Promise<any> {
    const result = await db.insert(taskComments).values({
      taskId,
      authorId,
      comment,
      proofUrl,
    } as any).returning();
    return (result as any[])[0];
  }

  async getTaskComments(taskId: number): Promise<any[]> {
    const comments = await db.query.taskComments.findMany({
      where: eq(taskComments.taskId, taskId),
      with: {
        author: {
          columns: {
            password: false,
          },
        },
      },
      orderBy: (taskComments, { desc }) => [desc(taskComments.createdAt)],
    });
    return comments;
  }

  async getTaskCommentById(commentId: number): Promise<any | null> {
    const comment = await db.query.taskComments.findFirst({
      where: eq(taskComments.id, commentId),
      with: {
        author: {
          columns: {
            password: false,
          },
        },
      },
    });
    return comment || null;
  }

  async deleteTaskComment(commentId: number): Promise<any> {
    const result = await db.delete(taskComments).where(eq(taskComments.id, commentId)).returning();
    return (result as any[])[0];
  }

  async createTaskProof(taskId: number, submittedById: number, proofType: string, proofUrl: string, description?: string): Promise<any> {
    const result = await db.insert(taskProof).values({
      taskId,
      submittedById,
      proofType,
      proofUrl,
      description,
    } as any).returning();
    return (result as any[])[0];
  }

  async getTaskProofs(taskId: number): Promise<any[]> {
    const proofs = await db.select().from(taskProof).where(eq(taskProof.taskId, taskId)).orderBy(desc(taskProof.submittedAt));
    return proofs;
  }

  async deleteTaskProof(proofId: number): Promise<any> {
    const result = await db.delete(taskProof).where(eq(taskProof.id, proofId)).returning();
    return (result as any[])[0];
  }

  async verifyTaskProof(proofId: number, verifiedById: number, verificationNotes?: string): Promise<any> {
    const result = await db.update(taskProof)
      .set({
        isVerified: true,
        verifiedById,
        verifiedAt: new Date(),
        verificationNotes,
      })
      .where(eq(taskProof.id, proofId))
      .returning();
    return (result as any[])[0];
  }

  async completeTask(taskId: number, completedById?: number): Promise<any> {
    const result = await db.update(weeklyMeetingTasks)
      .set({ isCompleted: true, completedAt: new Date(), completedById: completedById || 1 })
      .where(eq(weeklyMeetingTasks.id, taskId))
      .returning();
    return (result as any[])[0];
  }

  async uncompleteTask(taskId: number): Promise<any> {
    const result = await db.update(weeklyMeetingTasks)
      .set({ isCompleted: false, completedAt: null, completedById: null })
      .where(eq(weeklyMeetingTasks.id, taskId))
      .returning();
    return (result as any[])[0];
  }

  async updateTaskName(taskId: number, newTitle: string): Promise<any> {
    const result = await db.update(weeklyMeetingTasks)
      .set({ title: newTitle })
      .where(eq(weeklyMeetingTasks.id, taskId))
      .returning();
    return (result as any[])[0];
  }

  async deleteTask(taskId: number): Promise<any> {
    await db.delete(taskComments).where(eq(taskComments.taskId, taskId));
    await db.delete(taskProof).where(eq(taskProof.taskId, taskId));
    const result = await db.delete(weeklyMeetingTasks)
      .where(eq(weeklyMeetingTasks.id, taskId))
      .returning();
    return (result as any[])[0];
  }

  async updateDepartmentTaskProgress(taskId: number, departmentHeadId: number, updates: any): Promise<any> {
    const result = await db.update(departmentTaskProgress).set(updates)
      .where((col: any) => col.and(eq(departmentTaskProgress.taskId, taskId), eq(departmentTaskProgress.departmentHeadId, departmentHeadId)))
      .returning();
    return (result as any[])[0];
  }

  async getWeeklyMeetingArchive(meetingId: number): Promise<any[]> {
    return await db.select().from(weeklyMeetingArchive).where(eq(weeklyMeetingArchive.meetingId, meetingId));
  }

  async archiveWeeklyMeeting(meetingId: number, archivedById: number, resultsData: any): Promise<any> {
    const meeting = await this.getWeeklyMeeting(meetingId);
    const tasks = await this.getWeeklyMeetingTasks(meetingId);
    const result = await db.insert(weeklyMeetingArchive).values({
      meetingId,
      meetingData: JSON.stringify(meeting),
      tasksData: JSON.stringify(tasks),
      resultsData: JSON.stringify(resultsData),
      archivedById,
    } as any).returning();
    await db.update(weeklyMeetings).set({ status: "archived" as any }).where(eq(weeklyMeetings.id, meetingId));
    return (result as any[])[0];
  }

  // IT Support methods
  async createItSupportTicket(data: InsertItSupportTicket): Promise<ItSupportTicket> {
    return await executeWithRetry(async () => {
      const result = await db.insert(itSupportTickets).values(data as any).returning();
      return (result as ItSupportTicket[])[0];
    });
  }

  async getItSupportTickets(): Promise<ItSupportTicket[]> {
    return await executeWithRetry(async () => {
      return await db.select().from(itSupportTickets).orderBy(desc(itSupportTickets.createdAt)) as ItSupportTicket[];
    });
  }

  async getItSupportTicketsByUser(userId: number): Promise<ItSupportTicket[]> {
    return await executeWithRetry(async () => {
      return await db.select().from(itSupportTickets)
        .where(eq(itSupportTickets.requestedById, userId))
        .orderBy(desc(itSupportTickets.createdAt)) as ItSupportTicket[];
    });
  }

  async getItSupportTicket(id: number): Promise<ItSupportTicket | undefined> {
    return await executeWithRetry(async () => {
      const result = await db.select().from(itSupportTickets).where(eq(itSupportTickets.id, id));
      return (result as ItSupportTicket[])[0] || undefined;
    });
  }

  async updateItSupportTicket(id: number, updates: Partial<ItSupportTicket>): Promise<ItSupportTicket | undefined> {
    return await executeWithRetry(async () => {
      const result = await db.update(itSupportTickets)
        .set({ ...updates, updatedAt: new Date() } as any)
        .where(eq(itSupportTickets.id, id))
        .returning();
      return (result as ItSupportTicket[])[0] || undefined;
    });
  }

  async deleteItSupportTicket(id: number): Promise<boolean> {
    return await executeWithRetry(async () => {
      const result = await db.delete(itSupportTickets).where(eq(itSupportTickets.id, id)).returning();
      return result.length > 0;
    });
  }
}

// Using DatabaseStorage to access the actual database with all the big data
export const storage = new DatabaseStorage();

